var shareSvc *shareService.Service
var storageSvc storage.StorageInterface
var userSvc = userService.NewService()
var transferLogRepo = dao.NewTransferLogRepository()

// 配置常量（应从配置读取，这里使用默认值）
const (
	defaultMaxUploadSize = 10485760 // 10MB
	defaultBaseURL       = "http://localhost:12345"
	shareAccessTokenTTL  = 12 * time.Hour
)

func getStorageService() storage.StorageInterface {
	if storageSvc == nil {
		dataPath := "./data"
		if cfg := conf.GetGlobalConfig(); cfg != nil && cfg.App.DataPath != "" {
			dataPath = cfg.App.DataPath
		}
		storageSvc = storage.NewStorageService(&storage.StorageConfig{
			Type:     storage.StorageTypeLocal,
			DataPath: dataPath,
			BaseURL:  defaultBaseURL,
		})
	}
	return storageSvc
}

func getShareService() *shareService.Service {
	if shareSvc == nil {
		shareSvc = shareService.NewService(defaultBaseURL, getStorageService())
		shareSvc.SetUserService(userSvc)
	}
	return shareSvc
}

func buildShareLinks(c *app.RequestContext, code string) (string, string, string) {
	sharePath := fmt.Sprintf("/share/%s", code)
	fullShareURL := httpurl.BuildPublicShareURL(c, code)
	return sharePath, fullShareURL, fullShareURL
}

func isTextShare(fileCode *dbmodel.FileCode) bool {
	return fileCode != nil && fileCode.FilePath == ""
}

func displayFileName(fileCode *dbmodel.FileCode) string {
	if fileCode == nil {
		return ""
	}
	if fileCode.FilePath != "" && fileCode.Text != "" {
		return fileCode.Text
	}
	if fileCode.UUIDFileName != "" {
		return fileCode.UUIDFileName
	}
	if fileCode.Prefix != "" || fileCode.Suffix != "" {
		return fileCode.Prefix + fileCode.Suffix
	}
	return ""
}

func formatExpireTime(expireAt *time.Time) string {
	if expireAt == nil {
		return ""
	}
	return expireAt.Format("2006-01-02 15:04:05")
}

func writeSharePasswordError(c *app.RequestContext, statusCode int, err error) {
	if err == nil {
		return
	}

	message := "访问密码错误"
	switch {
	case errors.Is(err, shareService.ErrPasswordRequired):
		message = "需要访问密码"
	case errors.Is(err, shareService.ErrPasswordNotConfigured):
		message = "此分享的访问密码未正确设置，请联系分享者重新创建"
	case errors.Is(err, shareService.ErrInvalidPassword):
		message = "访问密码错误"
	}

	c.JSON(statusCode, map[string]interface{}{
		"code":    403,
		"message": message,
		"data": map[string]interface{}{
			"has_password": true,
		},
	})
}

func writeShareAuthInternalError(c *app.RequestContext, err error) {
	c.JSON(consts.StatusInternalServerError, map[string]interface{}{
		"code":    500,
		"message": fmt.Sprintf("访问授权失败: %v", err),
	})
}

func shareTokenSecret() string {
	if cfg := conf.GetGlobalConfig(); cfg != nil {
		if secret := strings.TrimSpace(cfg.User.JWTSecret); secret != "" {
			return "share-access:" + secret
		}
	}
	return "share-access:FileCodeBox2025JWT"
}

func isSecureShareRequest(c *app.RequestContext) bool {
	if c == nil {
		return false
	}

	if strings.EqualFold(strings.TrimSpace(string(c.GetHeader("X-Forwarded-Proto"))), "https") {
		return true
	}

	return strings.EqualFold(strings.TrimSpace(string(c.Request.Scheme())), "https")
}

func shareAccessExpiry(fileCode *dbmodel.FileCode, now time.Time) time.Time {
	expiresAt := now.Add(shareAccessTokenTTL)
	if fileCode != nil && fileCode.ExpiredAt != nil && fileCode.ExpiredAt.Before(expiresAt) {
		return fileCode.ExpiredAt.UTC()
	}
	return expiresAt.UTC()
}

func clearShareAccessCookie(c *app.RequestContext, code string) {
	if c == nil || strings.TrimSpace(code) == "" {
		return
	}

	c.SetCookie(
		sharetoken.CookieName(code),
		"",
		-1,
		"/share",
		"",
		protocol.CookieSameSiteLaxMode,
		isSecureShareRequest(c),
		true,
	)
}

func issueShareAccessCookie(c *app.RequestContext, fileCode *dbmodel.FileCode) error {
	if c == nil || fileCode == nil || !fileCode.RequireAuth {
		return nil
	}

	now := time.Now().UTC()
	expiresAt := shareAccessExpiry(fileCode, now)
	if !expiresAt.After(now) {
		return sharetoken.ErrExpiredToken
	}

	token, err := sharetoken.Sign(fileCode.Code, expiresAt, shareTokenSecret())
	if err != nil {
		return err
	}

	maxAge := int(expiresAt.Sub(now).Seconds())
	if maxAge < 1 {
		maxAge = 1
	}

	c.SetCookie(
		sharetoken.CookieName(fileCode.Code),
		token,
		maxAge,
		"/share",
		"",
		protocol.CookieSameSiteLaxMode,
		isSecureShareRequest(c),
		true,
	)
	return nil
}

func authorizeShareAccess(c *app.RequestContext, fileCode *dbmodel.FileCode, password string) error {
	if fileCode == nil || !fileCode.RequireAuth {
		return nil
	}

	cookieToken := strings.TrimSpace(string(c.Cookie(sharetoken.CookieName(fileCode.Code))))
	if cookieToken != "" {
		if _, err := sharetoken.Verify(cookieToken, fileCode.Code, shareTokenSecret(), time.Now().UTC()); err == nil {
			return nil
		}
		clearShareAccessCookie(c, fileCode.Code)
	}

	if err := getShareService().ValidateAccess(fileCode, password); err != nil {
		return err
	}

	return issueShareAccessCookie(c, fileCode)
}

func recordTransferLog(ctx context.Context, c *app.RequestContext, operation string, fileCode *dbmodel.FileCode) {
	if fileCode == nil {
		return
	}

	var userID *uint
	var username string
	if uid, exists := c.Get("user_id"); exists {
		if parsedID, ok := uid.(uint); ok {
			userID = &parsedID
		}
	}
	if uname, exists := c.Get("username"); exists {
		if parsedName, ok := uname.(string); ok {
			username = parsedName
		}
	}

	fileName := displayFileName(fileCode)
	if fileName == "" && isTextShare(fileCode) {
		fileName = "text-share.txt"
	}

	_ = transferLogRepo.Create(ctx, &dbmodel.TransferLog{
		Operation:  operation,
		FileCodeID: fileCode.ID,
		FileCode:   fileCode.Code,
		FileName:   fileName,
		FileSize:   fileCode.Size,
		UserID:     userID,
		Username:   username,
		IP:         c.ClientIP(),
	})
}

// ShareText .
// @router /share/text/ [POST]
func ShareText(ctx context.Context, c *app.RequestContext) {
	var err error
	var req sharemodel.ShareTextReq
	err = c.BindAndValidate(&req)
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": err.Error(),
		})
		return
	}

	// 空文本验证：拒绝空文本或只包含空白字符的文本
	if strings.TrimSpace(req.Text) == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "分享内容不能为空",
		})
		return
	}

	// XSS 防护：对文本内容进行 HTML 转义
	safeText := html.EscapeString(req.Text)
	password := c.DefaultPostForm("password", "")
	if req.RequireAuth && strings.TrimSpace(password) == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "开启访问保护后必须设置访问密码",
		})
		return
	}

	// 获取用户ID（如果有）
	var userID *uint
	if uid, exists := c.Get("user_id"); exists {
		if uidUint, ok := uid.(uint); ok {
			userID = &uidUint
		}
	}

	// 获取客户端 IP
	ownerIP := c.ClientIP()

	// 调用 service（使用转义后的安全文本）
	result, err := getShareService().ShareTextWithAuth(
		ctx,
		safeText,
		int(req.ExpireValue),
		req.ExpireStyle,
		req.RequireAuth,
		password,
		userID,
		ownerIP,
	)
	if err != nil {
		if errors.Is(err, shareService.ErrPasswordRequired) {
			c.JSON(consts.StatusBadRequest, map[string]interface{}{
				"code":    400,
				"message": "开启访问保护后必须设置访问密码",
			})
			return
		}
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": err.Error(),
		})
		return
	}

	shareURL, fullShareURL, qrCodeData := buildShareLinks(c, result.Code)
	createdFile, _ := getShareService().GetFileByCode(ctx, result.Code)
	recordTransferLog(ctx, c, "upload", createdFile)

	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "分享成功",
		"data": map[string]interface{}{
			"code":           result.Code,
			"share_url":      shareURL,
			"full_share_url": fullShareURL,
			"qr_code_data":   qrCodeData,
		},
	})
}

// ShareFile .
// @router /share/file/ [POST]
func ShareFile(ctx context.Context, c *app.RequestContext) {
	// 1. 解析表单参数
	expireValueStr := c.DefaultPostForm("expire_value", "1")
	expireStyle := c.DefaultPostForm("expire_style", "day")
	requireAuth := c.DefaultPostForm("require_auth", "false") == "true"
	password := c.DefaultPostForm("password", "")
	if requireAuth && strings.TrimSpace(password) == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "开启访问保护后必须设置访问密码",
		})
		return
	}

	expireValue, err := strconv.Atoi(expireValueStr)
	if err != nil {
		expireValue = 1
	}

	// 2. 获取上传文件
	file, err := c.FormFile("file")
	if err != nil {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "请上传文件",
		})
		return
	}

	// 3. 检查文件大小
	if file.Size > defaultMaxUploadSize {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": fmt.Sprintf("文件大小超过限制（最大 %d MB）", defaultMaxUploadSize/1024/1024),
		})
		return
	}

	// 4. 生成唯一文件名
	originalFilename := file.Filename
	fileExt := filepath.Ext(originalFilename)
	uuidFileName := uuid.New().String() + fileExt

	// 5. 生成存储路径（按日期分目录）
	now := time.Now()
	relativePath := filepath.Join(
		"uploads",
		now.Format("2006"),
		now.Format("01"),
		now.Format("02"),
	)
	savePath := filepath.Join(relativePath, uuidFileName)

	// 6. 保存文件到存储
	storageSvc := getStorageService()
	result, err := storageSvc.SaveFile(ctx, file, savePath)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": fmt.Sprintf("文件保存失败: %v", err),
		})
		return
	}

	// 7. 计算过期时间
	expireTime := utils.CalculateExpireTime(expireValue, expireStyle)
	expireCount := utils.CalculateExpireCount(expireStyle, expireValue)

	// 8. 获取用户ID（如果有）
	var userID *uint
	if uid, exists := c.Get("user_id"); exists {
		if uidUint, ok := uid.(uint); ok {
			userID = &uidUint
		}
	}

	// 9. 获取客户端 IP
	ownerIP := c.ClientIP()

	// 10. 确定上传类型
	uploadType := "anonymous"
	if userID != nil {
		uploadType = "authenticated"
	}

	// 11. 构建分享请求
	shareReq := &shareService.ShareFileReq{
		FilePath:       relativePath,
		FileName:       originalFilename,
		StoredName:     uuidFileName,
		Size:           result.FileSize,
		ExpiredAt:      expireTime,
		ExpiredCount:   expireCount,
		RequireAuth:    requireAuth,
		AccessPassword: password,
		UserID:         userID,
		UploadType:     uploadType,
		OwnerIP:        ownerIP,
		FileHash:       result.FileHash,
	}

	// 12. 调用 service 创建分享记录
	shareResult, err := getShareService().ShareFile(ctx, shareReq)
	if err != nil {
		if errors.Is(err, shareService.ErrPasswordRequired) {
			c.JSON(consts.StatusBadRequest, map[string]interface{}{
				"code":    400,
				"message": "开启访问保护后必须设置访问密码",
			})
			return
		}
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": fmt.Sprintf("创建分享记录失败: %v", err),
		})
		return
	}

	createdFile, _ := getShareService().GetFileByCode(ctx, shareResult.Code)
	recordTransferLog(ctx, c, "upload", createdFile)

	shareURL, fullShareURL, qrCodeData := buildShareLinks(c, shareResult.Code)
	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "文件上传成功",
		"data": map[string]interface{}{
			"code":           shareResult.Code,
			"share_url":      shareURL,
			"full_share_url": fullShareURL,
			"qr_code_data":   qrCodeData,
		},
	})
}

// GetUserShares 获取用户的分享列表
// @router /share/user [GET]
func GetUserShares(ctx context.Context, c *app.RequestContext) {
	// 获取用户ID（需要登录）
	userIDVal, exists := c.Get("user_id")
	if !exists {
		c.JSON(consts.StatusUnauthorized, map[string]interface{}{
			"code":    401,
			"message": "请先登录",
		})
		return
	}

	userID, ok := userIDVal.(uint)
	if !ok {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "用户ID格式错误",
		})
		return
	}

	// 获取分页参数
	page := 1
	pageSize := 10
	if p := c.Query("page"); p != "" {
		fmt.Sscanf(p, "%d", &page)
	}
	if ps := c.Query("page_size"); ps != "" {
		fmt.Sscanf(ps, "%d", &pageSize)
	}

	// 调用 service
	files, total, err := getShareService().GetFilesByUserID(ctx, userID, page, pageSize)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": err.Error(),
		})
		return
	}

	// 转换为响应格式
	items := make([]map[string]interface{}, len(files))
	for i, f := range files {
		fileName := displayFileName(f)
		items[i] = map[string]interface{}{
			"code":           f.Code,
			"file_name":      fileName,
			"filename":       fileName,
			"size":           f.Size,
			"file_size":      f.Size,
			"upload_type":    map[bool]string{true: "text", false: "file"}[isTextShare(f)],
			"is_text_share":  isTextShare(f),
			"download_count": f.UsedCount,
			"used_count":     f.UsedCount,
			"created_at":     f.CreatedAt.Format("2006-01-02 15:04:05"),
		}
		if f.ExpiredAt != nil {
			items[i]["expire_time"] = f.ExpiredAt.Format("2006-01-02 15:04:05")
		}
	}

	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "获取成功",
		"data": map[string]interface{}{
			"items":     items,
			"files":     items,
			"total":     total,
			"page":      page,
			"page_size": pageSize,
		},
	})
}

// DeleteShare 删除分享
// @router /share/:code [DELETE]
func DeleteShare(ctx context.Context, c *app.RequestContext) {
	// 获取用户ID（需要登录）
	userIDVal, exists := c.Get("user_id")
	if !exists {
		c.JSON(consts.StatusUnauthorized, map[string]interface{}{
			"code":    401,
			"message": "请先登录",
		})
		return
	}

	userID, ok := userIDVal.(uint)
	if !ok {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "用户ID格式错误",
		})
		return
	}

	code := c.Param("code")
	if code == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "请提供分享码",
		})
		return
	}

	// 调用 service 删除分享
	err := getShareService().DeleteFileByCode(ctx, code, userID)
	if err != nil {
		// 根据错误类型返回不同的状态码
		errMsg := err.Error()
		if errMsg == "分享不存在" {
			c.JSON(consts.StatusNotFound, map[string]interface{}{
				"code":    404,
				"message": errMsg,
			})
			return
		}
		if errMsg == "无权限删除此分享" {
			c.JSON(consts.StatusForbidden, map[string]interface{}{
				"code":    403,
				"message": errMsg,
			})
			return
		}

		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": fmt.Sprintf("删除失败: %s", errMsg),
		})
		return
	}

	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "删除成功",
	})
}

// GetShare .
// @router /share/select/ [GET]
func GetShare(ctx context.Context, c *app.RequestContext) {
	code := c.Query("code")
	password := c.Query("password")

	if code == "" {
		c.JSON(consts.StatusOK, map[string]interface{}{
			"code":    400,
			"message": "请提供分享码",
		})
		return
	}

	// 获取分享内容
	fileCode, err := getShareService().GetFileByCode(ctx, code)
	if err != nil {
		c.JSON(consts.StatusOK, map[string]interface{}{
			"code":    404,
			"message": "分享不存在或已过期",
		})
		return
	}

	if err := authorizeShareAccess(c, fileCode, password); err != nil {
		if errors.Is(err, shareService.ErrPasswordRequired) ||
			errors.Is(err, shareService.ErrInvalidPassword) ||
			errors.Is(err, shareService.ErrPasswordNotConfigured) {
			writeSharePasswordError(c, consts.StatusOK, err)
			return
		}
		writeShareAuthInternalError(c, err)
		return
	}

	data := map[string]interface{}{
		"code":         fileCode.Code,
		"has_password": fileCode.RequireAuth,
		"expire_time":  formatExpireTime(fileCode.ExpiredAt),
	}

	if isTextShare(fileCode) {
		data["text"] = fileCode.Text
		data["upload_type"] = "text"
	} else {
		fileName := displayFileName(fileCode)
		data["name"] = fileName
		data["file_name"] = fileName
		data["size"] = fileCode.Size
		data["file_size"] = fileCode.Size
		data["upload_type"] = "file"
		data["url"] = httpurl.BuildAPIDownloadURL(c, fileCode.Code, "")
	}

	c.JSON(consts.StatusOK, map[string]interface{}{
		"code":    200,
		"message": "获取成功",
		"data":    data,
	})
}

// DownloadFile 下载分享文件
// @router /share/download [GET]
func DownloadFile(ctx context.Context, c *app.RequestContext) {
	code := c.Query("code")
	password := c.Query("password")

	if code == "" {
		c.JSON(consts.StatusBadRequest, map[string]interface{}{
			"code":    400,
			"message": "请提供分享码",
		})
		return
	}

	fileCode, err := getShareService().GetFileByCode(ctx, code)
	if err != nil {
		c.JSON(consts.StatusNotFound, map[string]interface{}{
			"code":    404,
			"message": "分享不存在或已过期",
		})
		return
	}

	if err := authorizeShareAccess(c, fileCode, password); err != nil {
		if errors.Is(err, shareService.ErrPasswordRequired) ||
			errors.Is(err, shareService.ErrInvalidPassword) ||
			errors.Is(err, shareService.ErrPasswordNotConfigured) {
			writeSharePasswordError(c, consts.StatusUnauthorized, err)
			return
		}
		writeShareAuthInternalError(c, err)
		return
	}

	// 更新下载次数
	if err := getShareService().UpdateFileUsage(ctx, code); err != nil {
		// 记录错误但不阻止下载
		fmt.Printf("更新下载次数失败: %v\n", err)
	}
	recordTransferLog(ctx, c, "download", fileCode)

	// 如果是文本分享，直接返回文本
	if isTextShare(fileCode) {
		c.Header("Content-Type", "text/plain; charset=utf-8")
		c.Header("Content-Disposition", `inline; filename="text.txt"`)
		c.SetBodyString(fileCode.Text)
		return
	}

	// 如果是文件分享，流式返回文件
	filePath := fileCode.GetFilePath()
	if filePath == "" {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": "文件路径为空",
		})
		return
	}

	// 获取文件读取器
	reader, fileSize, err := getStorageService().GetFileReader(ctx, filePath)
	if err != nil {
		c.JSON(consts.StatusInternalServerError, map[string]interface{}{
			"code":    500,
			"message": fmt.Sprintf("获取文件失败: %v", err),
		})
		return
	}
	defer reader.Close()

	// 设置文件下载头
	fileName := displayFileName(fileCode)
	if fileName == "" {
		fileName = fileCode.Code
	}
	c.Header("Content-Type", "application/octet-stream")
	c.Header("Content-Disposition", fmt.Sprintf(`attachment; filename="%s"`, fileName))
	c.Header("Content-Length", fmt.Sprintf("%d", fileSize))

	// 流式传输文件内容
	c.SetBodyStream(reader, int(fileSize))
}
